nally, add triethanolamine in the part D and mix until thickness and homogenous. Thickness and homogenous is reached. Process is completed.", "temperature_c": null, "ph_target": null, "mixing_speed_rpm": null, "mixing_time_min": null}'::jsonb, '{"appearance": null, "viscosity_cp": null, "density_g_ml": null, "shelf_life_months": null}'::jsonb, '[]'::jsonb, 'private_library', 'Jamil Abduljaleel — Personal Formula Library v2', 'Jamil Abduljaleel', 2026, 'FA-2026-X01766', 88, 'en', TRUE)
